import React, { useState } from 'react';
import { Send } from 'lucide-react';
import TrackList from '../components/TrackList';
import { getRecommendations } from '../utils/api';
import { MOOD_SUGGESTIONS } from '../utils/helpers';

const GENRE_OPTIONS = ['blues', 'classical', 'country', 'disco', 'hiphop', 'jazz', 'metal', 'pop', 'reggae', 'rock'];

export default function MoodRecommend({ playTrack, toggleLike, isLiked, currentTrack, isPlaying }) {
  const [moodText, setMoodText] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [selectedGenres, setSelectedGenres] = useState([]);

  const handleSubmit = async (e) => {
    e?.preventDefault();
    if (!moodText.trim()) return;
    setLoading(true);
    try {
      const data = await getRecommendations(moodText, selectedGenres);
      setResults(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSuggestion = (s) => {
    setMoodText(s);
    setTimeout(() => handleSubmit(), 100);
  };

  const toggleGenre = (g) => {
    setSelectedGenres(prev => prev.includes(g) ? prev.filter(x => x !== g) : [...prev, g]);
  };

  return (
    <div className="mood-page">
      <div className="mood-hero">
        <h1>How are you feeling?</h1>
        <p>Describe your mood and we'll find the perfect tracks for you</p>

        <form className="mood-input-wrap" onSubmit={handleSubmit}>
          <input
            className="mood-input"
            placeholder="e.g. I'm feeling happy and want to dance..."
            value={moodText}
            onChange={(e) => setMoodText(e.target.value)}
          />
          <button type="submit" className="mood-submit-btn" disabled={loading || !moodText.trim()}>
            {loading ? '⏳' : <Send size={18} />}
          </button>
        </form>

        <div className="mood-tags">
          {MOOD_SUGGESTIONS.map(s => (
            <button
              key={s}
              className={`mood-tag ${moodText === s ? 'active' : ''}`}
              onClick={() => handleSuggestion(s)}
            >
              {s}
            </button>
          ))}
        </div>
      </div>

      {/* Genre Filters */}
      <section style={{ marginBottom: 32 }}>
        <div className="section-title">
          <span>Filter by Genre</span>
          {selectedGenres.length > 0 && (
            <a onClick={() => setSelectedGenres([])}>Clear</a>
          )}
        </div>
        <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
          {GENRE_OPTIONS.map(g => (
            <button
              key={g}
              className={`mood-tag ${selectedGenres.includes(g) ? 'active' : ''}`}
              onClick={() => toggleGenre(g)}
              style={{ textTransform: 'capitalize' }}
            >
              {g}
            </button>
          ))}
        </div>
      </section>

      {/* Results */}
      {loading && (
        <div className="loading-wrap">
          <div className="spinner" />
          <p style={{ color: 'var(--text-subdued)' }}>Finding your perfect tracks...</p>
        </div>
      )}

      {results && !loading && (
        <section>
          {results.detected_moods?.length > 0 && (
            <div style={{ marginBottom: 20 }}>
              <p style={{ color: 'var(--text-subdued)', marginBottom: 10, fontSize: 14 }}>Detected moods:</p>
              <div className="detected-moods">
                {results.detected_moods.map(m => (
                  <span key={m} className="mood-badge">{m}</span>
                ))}
              </div>
            </div>
          )}

          <div className="section-title">
            <span>Recommended for You</span>
            <span style={{ fontSize: 14, color: 'var(--text-subdued)' }}>{results.count} tracks</span>
          </div>

          <TrackList
            tracks={results.tracks}
            playTrack={playTrack}
            toggleLike={toggleLike}
            isLiked={isLiked}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
          />

          <div style={{ marginTop: 24, textAlign: 'center' }}>
            <button
              className="mood-tag"
              onClick={handleSubmit}
              style={{ padding: '12px 32px', borderRadius: 30 }}
            >
              🔀 Refresh Recommendations
            </button>
          </div>
        </section>
      )}

      {!results && !loading && (
        <div className="empty-state">
          <div style={{ fontSize: 64, marginBottom: 16 }}>🎧</div>
          <h2>Tell us your mood</h2>
          <p>Type how you're feeling above and we'll curate the perfect playlist</p>
        </div>
      )}
    </div>
  );
}
